  customFetch<string[]>(getListMajorsUrl(), { ...options, method: 'GET' });

export const getListMajorsQueryKey = () => [getListMajorsUrl()] as const;

export const useListMajors = <TData = Awaited<ReturnType<typeof listMajors>>, TError = ErrorType<ApiError>>(
  options?: { query?: UseQueryOptions<Awaited<ReturnType<typeof listMajors>>, TError, TData> }
): UseQueryResult<TData, TError> => {
  const queryOptions = { queryKey: getListMajorsQueryKey(), queryFn: listMajors, ...options?.query };
  return useQuery(queryOptions);
};

